        for (long[] edge : edges) {
            sortedEdges.add(edge);
        }
        sortedEdges.sort((a, b) -> Long.compare(a[2], b[2]));

        // Union-Find (Disjoint Set Union) data structure
        long[] parent = new long[(int) n];
        long[] rank = new long[(int) n];

        for (long i = 0; i < n; i++) {
            parent[i] = i;
            rank[i] = 1;
        }

        long[] find = new long[2];
        find[0] = -1;
        find[1] = -1;

        long[] union = new long[2];
        union[0] = -1;
        union[1] = -1;

